public class AccountSummary {
    public String name;
    public Decimal revenue;
    public AccountSummary(Account a) {
        this.name = a.Name;
        this.revenue = a.AnnualRevenue;
    }
    public String pitch() {
        return name + ' ($' + revenue + ')';
    }
    public static AccountSummary fromAccount(Account a) {
        return new AccountSummary(a);
    }
}
